            setTradeField('selected-activity', fmtTradeInt(contract.volume) + ' / ' + fmtTradeInt(contract.open_interest));
            setTradeField('selected-greeks', fmtTradePct(contract.iv) + ' / ' + fmtTradeDelta(contract.delta));
